            for (int i = 0; i + l - 1 < n; i++) {
                int j = i + l - 1;
                if (l == 1) cost[i][j] = 0;
                else cost[i][j] = (s.charAt(i) == s.charAt(j) ? 0 : 1) + cost[i + 1][j - 1];
