                dp[i][j] = Integer.MAX_VALUE;
                for (int p = i - 2; p < j; p++) {
                    dp[i][j] = Math.min(dp[i][j], dp[i - 1][p] + cost[p + 1][j]);
                }
            }
        }
        return dp[k][n - 1];
    }
}
